77	export const postToApi = async <T>({
78	  url,
79	  headers = {},
80	  body,
81	  successfulResponseHandler,
82	  failedResponseHandler,
83	  abortSignal,
84	  fetch = getOriginalFetch(),
85	}: {
86	  url: string;
87	  headers?: Record<string, string | undefined>;
88	  body: {
89	    content: string | FormData | Uint8Array;
90	    values: unknown;
91	  };
92	  failedResponseHandler: ResponseHandler<Error>;
93	  successfulResponseHandler: ResponseHandler<T>;
94	  abortSignal?: AbortSignal;
95	  fetch?: FetchFunction;
96	}) => {
97	  try {
98	    const response = await fetch(url, {
99	      method: 'POST',
100	      headers: withUserAgentSuffix(
101	        headers,
102	        `ai-sdk/provider-utils/${VERSION}`,
103	        getRuntimeEnvironmentUserAgent(),
104	      ),
105	      body: body.content,
106	      signal: abortSignal,
107	    });
108	
109	    const responseHeaders = extractResponseHeaders(response);
110	
111	    if (!response.ok) {
112	      let errorInformation: {
113	        value: Error;
114	        responseHeaders?: Record<string, string> | undefined;
115	      };
116	
117	      try {
118	        errorInformation = await failedResponseHandler({
119	          response,
120	          url,
121	          requestBodyValues: body.values,
122	        });
123	      } catch (error) {
124	        if (isAbortError(error) || APICallError.isInstance(error)) {
125	          throw error;
126	        }
127	
128	        throw new APICallError({
129	          message: 'Failed to process error response',
130	          cause: error,
131	          statusCode: response.status,
132	          url,
133	          responseHeaders,
134	          requestBodyValues: body.values,
135	        });
136	      }
137	
138	      throw errorInformation.value;
139	    }
140	
141	    try {
142	      return await successfulResponseHandler({
143	        response,
144	        url,
145	        requestBodyValues: body.values,
146	      });
147	    } catch (error) {
148	      if (error instanceof Error) {
149	        if (isAbortError(error) || APICallError.isInstance(error)) {
150	          throw error;
151	        }
152	      }
153	
154	      throw new APICallError({
155	        message: 'Failed to process successful response',
156	        cause: error,
157	        statusCode: response.status,
158	        url,
159	        responseHeaders,
160	        requestBodyValues: body.values,
161	      });
162	    }
163	  } catch (error) {
164	    throw handleFetchError({ error, url, requestBodyValues: body.values });
165	  }
166	};
