import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import {
  PixelArtImageModel,
  PixelArtImageModelConfig,
} from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Public interfaces
// ---------------------------------------------------------------------------

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key.
   * Defaults to the value of the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API. Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful for middleware, testing, etc.
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image generation model.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   * Alias for `image()`.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? DEFAULT_BASE_URL;

  const getHeaders = (): Record<string, string | undefined> =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      'ai-sdk/pixelart/0.0.1',
    );

  const buildModelConfig = (): PixelArtImageModelConfig => ({
    provider: 'pixelart.image',
    url: ({ path }) => `${baseURL}${path}`,
    headers: getHeaders,
    fetch: options.fetch,
  });

  const createImageModel = (modelId: PixelArtImageModelId): ImageModelV3 =>
    new PixelArtImageModel(modelId, buildModelConfig());

  // PixelArt is image-only; throw for unsupported model types.
  const unsupportedLanguageModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };

  const unsupportedEmbeddingModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    languageModel: unsupportedLanguageModel,
    embeddingModel: unsupportedEmbeddingModel,
    image: createImageModel,
    imageModel: createImageModel,
  };
}

/**
 * Default PixelArt provider instance (reads API key from `PIXELART_API_KEY`).
 */
export const pixelart = createPixelArt();

