import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import { FetchFunction } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelartFailedResponseHandler } from './pixelart-error';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Internal config type
// ---------------------------------------------------------------------------

export interface PixelArtImageModelConfig {
  provider: string;
  url: (options: { modelId: string; path: string }) => string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Response schema (minimal – only the fields we actually need)
// ---------------------------------------------------------------------------

const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// ---------------------------------------------------------------------------
// Image model implementation
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /** PixelArt supports up to 4 images per call. */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // PixelArt API uses a `size` string, not an aspect ratio.
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use the `size` parameter or the `pixelart.size` provider option instead.',
      });
    }

    // seed is not supported by the PixelArt API.
    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    // Pull provider-specific options from the call options bag.
    const pixelartOptions = (providerOptions?.pixelart ??
      {}) as PixelArtImageSettings;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        // Provider option `size` takes precedence over the standard `size` param.
        size: pixelartOptions.size ?? size,
        // PixelArt-specific parameters
        style: pixelartOptions.style,
        pixel_density: pixelartOptions.pixelDensity,
        response_format: 'b64_json',
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created ?? undefined,
        },
      },
    };
  }
}

