import { FetchFunction } from '@ai-sdk/provider-utils';
import { PixelArtImageModelId } from './pixelart-image-settings';
export interface PixelArtImageModelConfig {
    provider: string;
    url: (options: {
        modelId: string;
        path: string;
    }) => string;
    headers: () => Record<string, string | undefined>;
    fetch?: FetchFunction;
    _internal?: {
        currentDate?: () => Date;
    };
}
export declare class PixelArtImageModel implements ImageModelV3 {
    readonly modelId: PixelArtImageModelId;
    private readonly config;
    readonly specificationVersion = "v3";
    /** PixelArt supports up to 4 images per call. */
    readonly maxImagesPerCall = 4;
    get provider(): string;
    constructor(modelId: PixelArtImageModelId, config: PixelArtImageModelConfig);
    doGenerate({ prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>>;
}
