/**
 * Known PixelArt image model IDs.
 * The `string & {}` union allows any string to be passed while still providing
 * IDE autocomplete for the well-known values.
 */
export type PixelArtImageModelId = 'pixelart-v1' | 'pixelart-v2' | 'pixelart-retro' | 'pixelart-8bit' | (string & {});
/**
 * Provider-specific settings for PixelArt image generation, passed via
 * `providerOptions.pixelart` at call time.
 */
export interface PixelArtImageSettings {
    /**
     * The output image size (e.g. "512x512", "1024x1024").
     * When provided, this overrides the top-level `size` parameter.
     */
    size?: string;
    /**
     * The rendering style to apply to the generated image.
     * - `pixel`  – standard pixel-art style
     * - `retro`  – retro/CRT-style pixel art
     * - `8bit`   – classic 8-bit game aesthetic
     */
    style?: 'pixel' | 'retro' | '8bit';
    /**
     * The pixel density of the generated image (dots per pixel grid cell).
     * Higher values produce finer detail. Typical range: 1–16.
     */
    pixelDensity?: number;
}
//# sourceMappingURL=pixelart-image-settings.d.ts.map
